rules.source:
// comment
/// doc comment
statute 1 "Comments" {
  elements { actus_reus conduct := "does the act"; }
}

statute 2 "Statute" {
  elements { all_of {
    actus_reus conduct := "does the act";
  } }
}

statute 3 "Burden" {
  elements { all_of {
    actus_reus taking := "takes property" burden prosecution beyond_reasonable_doubt;
  } }
}

statute 4 "Grouped" {
  elements { all_of {
    actus_reus conduct := "does the act";
    any_of {
      mens_rea intent := "intends it";
      mens_rea knowledge := "knows it";
    }
  } }
}

statute 5 "Exception" {
  elements { actus_reus conduct := "does the act"; }
  exception excuse {
    "excusing condition"
    "not liable"
  }
}

statute 6 "Case" {
  elements { actus_reus deception := "deceives"; }
  /// @role ratio
  /// @jurisdiction singapore
  /// @court_level apex
  /// @date 2026-01-01
  /// @effect requires active_misleading
  caselaw "PP v Tan" "[2026] SGCA 1" {
    "holding"
    element deception
  }
}

struct Facts {
  bool act,
}

statute 299 "Base" {
  elements { actus_reus act := "does the act"; }
}
fn run(Facts facts) : bool { return is_infringed(s299) && apply_scope(s299, facts); }
